    }

    /**
     * 测试正常路径：传入空字符串前缀，验证前缀设置正确
     */
    @Test
    void withPrefix_EmptyPrefix_SetsEmptyPrefix() {
        // 准备测试数据
        RouteImpl route = new RouteImpl();
        String expectedPrefix = "";

        // 执行目标方法
        route.withPrefix(expectedPrefix);

        // 断言结果：空前缀已正确设置
        assertEquals(expectedPrefix, route.getPrefix(), "设置空字符串前缀后，getPrefix应返回空字符串");
    }

    /**
     * 测试异常路径：传入null前缀，验证抛出IllegalArgumentException
     */
    @Test
    void withPrefix_NullPrefix_ThrowsIllegalArgumentException() {
        // 准备测试数据
        RouteImpl route = new RouteImpl();

        // 执行目标方法并捕获异常
        IllegalArgumentException exception = assertThrows(IllegalArgumentException.class,
                () -> route.withPrefix(null),
