```java
public class StateHolder {
    private List<String> items = new ArrayList<>();
    private boolean initialized = false;
    private boolean closed = false;
    private boolean hasUncommittedChanges = false;

    public void initialize() { initialized = true; }
    public void addItem(String item) { items.add(item); hasUncommittedChanges = true; }
    public int getItemCount() { return items.size(); }
    public List<String> getItems() { return new ArrayList<>(items); }
    public boolean hasUncommittedChanges() { return hasUncommittedChanges; }
    public void close() { closed = true; items.clear(); }
    public boolean isClosed() { return closed; }

    public void clear() {
        if (!initialized) {
            throw new IllegalStateException("StateHolder未初始化，无法执行clear操作");
        }
        if (closed) {
            throw new IllegalStateException("StateHolder已关闭，无法执行clear操作");
        }
        items.clear();
        hasUncommittedChanges = false;
    }
}
```

